#!/usr/bin/env python3
# Piece 1c-bench (dream-os) — give Kriya the FULL binder bench (dreamai PWA parity).
#
# Completes Kriya's bench to all 20 binder tools Donna held on the vendor PWA:
#   writes: money, money_edit, date, client, note, note_append, phone, stage, doc,
#           reasonforaction_append, hide, unarchive, EDIT, REPEATFOLLOWUP, MERGE, SPLIT
#   reads:  find, tally, history, WHATSDUE
# (The /desk bench — shelf/corpus/PDF/review/project — is deliberately NOT given:
#  that is the professional-functional EaIS world, not the wedding vertical.)
#
# Overwrites the three agent files with the full-bench versions. Pure overwrite,
# additive in behaviour (existing hands unchanged; 5 new hands added).

import base64, os, sys
ROOT=os.getcwd()
PAYLOADS={
    'src/agent/kriyaPrimitives.js': '',
    'src/agent/kriyaRead.js': '',
    'src/agent/kriyaTurn.js': '',
}
def main():
    if not os.path.isdir(os.path.join(ROOT,"src","agent")):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    for rel,b64 in PAYLOADS.items():
        open(os.path.join(ROOT,rel),"wb").write(base64.b64decode(b64)); print(f"OK: overwrote {rel}")
    print("\nPiece 1c-bench written. Kriya holds the full 20-tool binder bench (PWA parity).")
if __name__=="__main__": main()
